/* Minimal GCC GIMPLE pass: Count basic blocks per function
   This pass demonstrates the standard pattern for GIMPLE optimization passes
   following GCC's architectural conventions.
*/

#include "config.h"
#include "system.h"
#include "coretypes.h"
#include "backend.h"
#include "tree.h"
#include "gimple.h"
#include "tree-pass.h"
#include "tree-cfg.h"
#include "cfgloop.h"
#include "dumpfile.h"

namespace {

